import React, { useState, useContext } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import '../styles/auth.css';

const Register = () => {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isAdmin, setIsAdmin] = useState(false);
  const [adminSecret, setAdminSecret] = useState('');
  const { login } = useContext(AuthContext);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (isAdmin && !adminSecret) {
        alert('Please enter the admin secret code');
        return;
      }
      const res = await fetch('/api/auth/register', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name, email, password, adminSecret: isAdmin ? adminSecret : undefined })
      });
      const data = await res.json();
      if (res.ok) {
        alert('Registration Successful! Please check your email for the Welcome OTP.');
        login(data);
        navigate(data.role === 'admin' ? '/admin' : '/');
      } else {
        alert(data.message);
      }
    } catch (error) {
      console.error(error);
    }
  };

  const registerAsAdmin = async () => {
    const ADMIN_SECRET = process.env.REACT_APP_ADMIN_SECRET || 'ADMINCODE123';
    const secret = window.prompt('Enter admin secret code to register as admin:');
    if (!secret) return;
    if (secret !== ADMIN_SECRET) {
      alert('Incorrect admin secret');
      return;
    }
    try {
      const res = await fetch('/api/auth/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email: 'admin@shopnest.com', password: 'password123' })
      });
      const data = await res.json();
      if (res.ok) {
        alert('Logged in as Admin');
        login(data);
        navigate('/admin');
      } else {
        alert(data.message);
      }
    } catch (error) {
      console.error(error);
    }
  };

  return (
    <div className="auth-container">
      <form onSubmit={handleSubmit} className="auth-form">
        <h2>Register</h2>
        <input type="text" placeholder="Full Name" value={name} onChange={(e) => setName(e.target.value)} required />
        <input type="email" placeholder="Email" value={email} onChange={(e) => setEmail(e.target.value)} required />
        <input type="password" placeholder="Password" value={password} onChange={(e) => setPassword(e.target.value)} required />
        <div style={{ display: 'flex', gap: '8px', width: '100%' }}>
          <button type="submit" className="btn" style={{ flex: 1 }}>Register</button>
          <button type="button" className="btn" style={{ flex: 1, background: '#f97316' }} onClick={registerAsAdmin}>Register as Admin</button>
        </div>
        <p>Already have an account? <Link to="/login">Login</Link></p>
      </form>
    </div>
  );
};

export default Register;
